// Script: generar_69_chiqui_saludo_dashboard.js
// Que hace: agrega la imagen de Chiqui con pañoleta de color como
// saludo en el Dashboard, reemplazando el banner de texto simple.
// La pañoleta cambia automaticamente segun el estado del dia:
//   - Roja:     no ha registrado a su mascota hoy
//   - Azul:     registro hoy (estado normal)
//   - Verde:    registro hoy y todo esta bien (estado verde)
//   - Amarilla: registro hoy pero hay algo que merece atencion
//
// Las imagenes se guardan en /public/ para que Next.js las sirva
// como assets estaticos (igual que el logo y los iconos de la app).
//
// Como correrlo: node generar_69_chiqui_saludo_dashboard.js
// Confirma "OK" para los 5 archivos (4 imagenes + 1 componente)

const fs = require('fs');
const path = require('path');

function escribirB64(relPath, b64, encoding) {
  const filePath = path.join(...relPath.split('/'));
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  if (encoding === 'binary') {
    fs.writeFileSync(filePath, Buffer.from(b64, 'base64'));
  } else {
    fs.writeFileSync(filePath, Buffer.from(b64, 'base64').toString('utf8'));
  }
  console.log('OK: ' + filePath);
}

escribirB64('public/chiqui-roja.png', "", 'binary');
escribirB64('public/chiqui-azul.png', "", 'binary');
escribirB64('public/chiqui-verde.png', "", 'binary');
escribirB64('public/chiqui-amarilla.png', "", 'binary');
escribirB64('components/DashboardContenido.tsx', "", 'utf8');
